'use client';
import { useRouter, useSearchParams } from 'next/navigation';
import { useReducer, useRef, useState } from 'react';
import {
  SRAppReducer,
  initialSRAppState,
  SRAppContextProps,
  SRAppContext,
} from '../../sr_context';
import useAxiosAuth from '@/hooks/AxiosAuth';
import { useMutation, useQuery, useQueryClient } from 'react-query';
import { deleteSite, getSiteDetail } from '../../api';
import { WithSiteDetailSidebar } from '@/components/Sign_Register_App/Site_Manage_Detail/Sidebar';
import { Site } from '@/app/type/Sign_Register_Sites';
import CustomInfoModal from '@/components/CustomDeleteModel';
import CreateManageSitesModel from '@/components/Sign_Register_App/Models/Manage_Sites_Models/Create_Manage_Sites';
